    fn test_console_print_basic() {
        let tc = TestConsole::new();
        tc.console().print("Hello, world!");
        tc.assert_contains("Hello, world!");
    }

    #[test]
    fn test_console_print_styled_in_human_mode() {
        let tc = TestConsole::new_rich();
        tc.console().print("[bold red]Error[/]");

        // Should contain the text
        tc.assert_contains("Error");

        // Raw output should have ANSI codes
        let raw = tc.raw_output().join("");
        assert!(raw.contains("\x1b["), "Rich mode should produce ANSI codes");
    }

    #[test]
    fn test_console_print_plain_in_agent_mode() {
        let tc = TestConsole::new(); // Agent mode by default
        tc.console().print("[bold red]Error[/]");

        // Should just have plain text
        let raw = tc.raw_output().join("");
        assert!(!raw.contains("\x1b["), "Agent mode should not produce ANSI codes");
    }

    #[test]
    fn test_console_print_renderable() {
        use rich_rust::Panel;

        let tc = TestConsole::new_rich();
        let panel = Panel::from_text("Content").title("Title");
